<template><div><h2>📚 知识库</h2><el-button type="primary" size="small" @click="show=true;reset()">+ 添加文章</el-button><el-input v-model="kw" placeholder="搜索..." style="max-width:260px;margin:0 8px" @input="fetch(kw)"/><div v-for="k in list" :key="k.id" style="background:#F8FAFC;border-radius:10px;padding:12px 16px;margin:8px 0"><b>{{ k.title }}</b><span style="color:#64748B;font-size:12px;margin-left:8px">📁 {{ k.category }} · 👁 {{ k.view_count }}</span></div><el-dialog v-model="show" title="添加"><el-form label-width="50px"><el-form-item label="标题"><el-input v-model="f.title"/></el-form-item><el-form-item label="分类"><el-input v-model="f.category"/></el-form-item><el-form-item label="标签"><el-input v-model="f.tags"/></el-form-item><el-form-item label="内容"><el-input v-model="f.content" type="textarea" :rows="4"/></el-form-item></el-form><template #footer><el-button @click="show=false">取消</el-button><el-button type="primary" @click="save">保存</el-button></template></el-dialog></div></template>
<script setup>import {ref,reactive,onMounted} from 'vue';import request from '@/utils/request';import {ElMessage} from 'element-plus';const list=ref([]);const show=ref(false);const kw=ref('');const f=reactive({title:'',category:'',tags:'',content:''});function reset(){Object.assign(f,{title:'',category:'',tags:'',content:''})}async function fetch(q){try{list.value=await request.get('/knowledge-base'+(q?'?keyword='+encodeURIComponent(q):''))||[]}catch{}}async function save(){try{await request.post('/knowledge-base',f);show.value=false;fetch();ElMessage.success('已添加')}catch{}}onMounted(()=>fetch())</script>
